import{_ as t,c as e,o as a,V as l}from"./chunks/framework.vTT8XiEL.js";const p=JSON.parse('{"title":"【跑图经验】🏠家 => 🏙公司","description":null,"frontmatter":{"tag":"生活","description":null,"outline":[2,3]},"headers":[],"relativePath":"essay/life/home2company.md","filePath":"essay/life/home2company.md","lastUpdated":1705208598000}'),n={name:"essay/life/home2company.md"},r=l('<h1 id="【跑图经验】🏠家-🏙公司" tabindex="-1">【跑图经验】🏠家 =&gt; 🏙公司 <a class="header-anchor" href="#【跑图经验】🏠家-🏙公司" aria-label="Permalink to &quot;【跑图经验】🏠家 =&gt; 🏙公司&quot;">​</a></h1><p>在<a href="https://sugarat.top/offer/experience/2023summary.html" target="_blank" rel="noreferrer">23年的总结</a>里提到了，23年底从租的房子搬到新家。</p><p>自从 21 年毕业出来上班后，交通工具基本就是 自行车/小电驴，选的都是离公司都是比较近的小区。</p><p>但现在，上班的交通工具变成公共出行工具（公交/地铁/滴滴）。</p><p><strong>为了早上多睡一会儿，又不迟到(早9.30)，需要总结出一条时间最短的线路</strong>，于是就有了这篇笔记，在最佳的方案出来前，它将记录这个（上班）过程。</p><h2 id="纯地铁" tabindex="-1">纯地铁 <a class="header-anchor" href="#纯地铁" aria-label="Permalink to &quot;纯地铁&quot;">​</a></h2><p>花费：日常9折，雾霾天8折（平均一趟 4 RMB）。</p><p><em>参与了个啥绑卡活动，目前上班这一程只要 1 分钱。</em></p><h3 id="_7-1-pass" tabindex="-1">7-1（pass） <a class="header-anchor" href="#_7-1-pass" aria-label="Permalink to &quot;7-1（pass）&quot;">​</a></h3><p>线路：家 =&gt; 7号线 =&gt; 1号线 =&gt; 公司</p><table><thead><tr><th style="text-align:center;">时间（MM-DD）</th><th style="text-align:center;">出门=&gt;上班滴卡（min - time）</th><th style="text-align:center;">地铁（min）</th><th style="text-align:center;">花费（￥）</th></tr></thead><tbody><tr><td style="text-align:center;">01-02</td><td style="text-align:center;">77 (08:08=&gt;09:24)</td><td style="text-align:center;">51</td><td style="text-align:center;">4</td></tr></tbody></table><p>7号线转1号线太恼火了，挤了1次就够了，这个换乘花费了20分钟，这个线路不太合适 ❌。</p><h3 id="_7-18-1-ing" tabindex="-1">7-18-1（ing） <a class="header-anchor" href="#_7-18-1-ing" aria-label="Permalink to &quot;7-18-1（ing）&quot;">​</a></h3><p>线路：家 =&gt; 7号线 =&gt; 18号线 =&gt; 1号线 =&gt; 公司</p><p>优点</p><ul><li>7 =&gt; 18号线能保证一次就上车</li><li>18 =&gt; 1号线能保证2次（最差）就上车</li></ul><p>缺点</p><ul><li>换乘时间长：换乘路线长，下车上扶梯人多排队时间不确定</li></ul><h4 id="week1" tabindex="-1">week1 <a class="header-anchor" href="#week1" aria-label="Permalink to &quot;week1&quot;">​</a></h4><table><thead><tr><th style="text-align:center;">时间（MM-DD）</th><th style="text-align:center;">出门=&gt;上班滴卡（min - time）</th><th style="text-align:center;">地铁（min）</th><th style="text-align:center;">花费（￥）</th></tr></thead><tbody><tr><td style="text-align:center;">01-03</td><td style="text-align:center;">55 (08:14=&gt;09:09)</td><td style="text-align:center;">41</td><td style="text-align:center;">0.01</td></tr><tr><td style="text-align:center;">01-04</td><td style="text-align:center;">61 (08:07=&gt;09:08)</td><td style="text-align:center;">42</td><td style="text-align:center;">0.01</td></tr><tr><td style="text-align:center;">01-05</td><td style="text-align:center;">60 (08:05=&gt;09:05)</td><td style="text-align:center;">42</td><td style="text-align:center;">0.01</td></tr></tbody></table><p>平均1小时，地铁里大约40分钟；还有20分钟走路上。</p><p>优化空间</p><ul><li>地铁里：减少换乘时间（确定一个下车离扶梯近的）</li><li>地铁外（待定）：走快一点，加个坐骑</li></ul><p>下周目标：<strong>记最优车厢位置</strong>，地铁上的时间减少到 &lt; 40min，全路程时间 &lt; 55min。</p><h4 id="week2" tabindex="-1">week2 <a class="header-anchor" href="#week2" aria-label="Permalink to &quot;week2&quot;">​</a></h4><table><thead><tr><th style="text-align:center;">时间（MM-DD）</th><th style="text-align:center;">出门=&gt;上班滴卡</th><th style="text-align:center;">地铁（min）</th><th style="text-align:center;">花费（￥）</th></tr></thead><tbody><tr><td style="text-align:center;">01-08</td><td style="text-align:center;">64</td><td style="text-align:center;">40</td><td style="text-align:center;">0.01</td></tr><tr><td style="text-align:center;">01-09</td><td style="text-align:center;">65</td><td style="text-align:center;">38</td><td style="text-align:center;">0.01</td></tr><tr><td style="text-align:center;">01-10</td><td style="text-align:center;">65</td><td style="text-align:center;">39</td><td style="text-align:center;">0.01</td></tr><tr><td style="text-align:center;">01-12</td><td style="text-align:center;">62</td><td style="text-align:center;">40</td><td style="text-align:center;">0.01</td></tr></tbody></table><p>优化了一下上下车点位，地铁里能保持在 &lt;= 40 min，路上不急就可以慢悠悠的走咯。</p><h2 id="🚧-打车待定" tabindex="-1">🚧 打车待定 <a class="header-anchor" href="#🚧-打车待定" aria-label="Permalink to &quot;🚧 打车待定&quot;">​</a></h2><h2 id="🚧-公交待定" tabindex="-1">🚧 公交待定 <a class="header-anchor" href="#🚧-公交待定" aria-label="Permalink to &quot;🚧 公交待定&quot;">​</a></h2>',29),i=[r];function d(s,c,h,o,g,y){return a(),e("div",null,i)}const m=t(n,[["render",d]]);export{p as __pageData,m as default};
